import json
from ortools.sat.python import cp_model

availability = [3, 2, 2]
demand = [180, 160]
capabilities = [
    [60, 40],
    [90, 80],
    [30, 120],
]
costs = [
    [110, 70],
    [180, 140],
    [90, 260],
]

num_aircraft = len(availability)
num_routes = len(demand)

model = cp_model.CpModel()

allocation = {}
for a in range(num_aircraft):
    for r in range(num_routes):
        allocation[a, r] = model.NewIntVar(0, availability[a], f"allocation_{a}_{r}")

for a in range(num_aircraft):
    model.Add(sum(allocation[a, r] for r in range(num_routes)) <= availability[a])

for r in range(num_routes):
    model.Add(
        sum(allocation[a, r] * capabilities[a][r] for a in range(num_aircraft))
        == demand[r]
    )

model.Minimize(
    sum(
        costs[a][r] * allocation[a, r]
        for a in range(num_aircraft)
        for r in range(num_routes)
    )
)

solver = cp_model.CpSolver()
status = solver.Solve(model)

result = [int(solver.ObjectiveValue())]
print(json.dumps(result))

