import json
from ortools.sat.python import cp_model

earliest = [3, 6, 7]
latest = [14, 19, 24]
target = [5, 10, 12]
penalty_after = [16, 19, 25]
penalty_before = [6, 9, 12]
separation = [
    [0, 7, 8],
    [7, 0, 6],
    [8, 6, 0],
]

n = len(earliest)
model = cp_model.CpModel()

landing = [
    model.NewIntVar(earliest[i], latest[i], f"landing_{i}")
    for i in range(n)
]
early = [
    model.NewIntVar(0, target[i] - earliest[i], f"early_{i}")
    for i in range(n)
]
late = [
    model.NewIntVar(0, latest[i] - target[i], f"late_{i}")
    for i in range(n)
]

for i in range(n):
    model.Add(early[i] >= target[i] - landing[i])
    model.Add(late[i] >= landing[i] - target[i])

for i in range(n):
    for j in range(i + 1, n):
        i_before_j = model.NewBoolVar(f"order_{i}_{j}")
        j_before_i = model.NewBoolVar(f"order_{j}_{i}")
        model.Add(i_before_j + j_before_i == 1)
        model.Add(landing[j] >= landing[i] + separation[i][j]).OnlyEnforceIf(i_before_j)
        model.Add(landing[i] >= landing[j] + separation[j][i]).OnlyEnforceIf(j_before_i)

model.Minimize(
    sum(
        penalty_before[i] * early[i] + penalty_after[i] * late[i]
        for i in range(n)
    )
)

solver = cp_model.CpSolver()
solver.parameters.num_search_workers = 1
status = solver.Solve(model)

if status in (cp_model.OPTIMAL, cp_model.FEASIBLE):
    result = [int(solver.ObjectiveValue())]
else:
    result = []

print(json.dumps(result))

import json
from ortools.sat.python import cp_model

earliest = [0, 4, 7, 10]
latest = [18, 22, 25, 30]
target = [5, 9, 14, 20]
penalty_after = [9, 11, 13, 10]
penalty_before = [6, 8, 7, 5]
separation = [
    [0, 3, 4, 5],
    [3, 0, 3, 4],
    [4, 3, 0, 3],
    [5, 4, 3, 0],
]

n = len(earliest)
model = cp_model.CpModel()

landing = [
    model.NewIntVar(earliest[i], latest[i], f"landing_{i}")
    for i in range(n)
]
early = [
    model.NewIntVar(0, max(target[i] - earliest[i], latest[i] - target[i]), f"early_{i}")
    for i in range(n)
]
late = [
    model.NewIntVar(0, max(target[i] - earliest[i], latest[i] - target[i]), f"late_{i}")
    for i in range(n)
]

order = {}
for i in range(n):
    for j in range(n):
        if i != j:
            order[i, j] = model.NewBoolVar(f"order_{i}_{j}")

for i in range(n):
    model.Add(landing[i] >= earliest[i])
    model.Add(landing[i] <= latest[i])
    model.Add(early[i] >= target[i] - landing[i])
    model.Add(late[i] >= landing[i] - target[i])

horizon = max(latest) - min(earliest) + max(max(row) for row in separation)
for i in range(n):
    for j in range(i + 1, n):
        model.Add(order[i, j] + order[j, i] == 1)

for i in range(n):
    for j in range(n):
        if i != j:
            model.Add(landing[j] >= landing[i] + separation[i][j] - horizon * (1 - order[i, j]))

model.Minimize(
    sum(penalty_before[i] * early[i] + penalty_after[i] * late[i] for i in range(n))
)

solver = cp_model.CpSolver()
solver.parameters.num_search_workers = 1
status = solver.Solve(model)

if status not in (cp_model.OPTIMAL, cp_model.FEASIBLE):
    result = []
else:
    result = [int(round(solver.ObjectiveValue()))]

print(json.dumps(result))

