from ortools.sat.python import cp_model

earliest = [1, 3, 5, 6, 8]
latest = [12, 15, 17, 21, 24]
target = [4, 6, 8, 10, 12]
penalty_after = [10, 9, 7, 12, 11]
penalty_before = [3, 4, 8, 5, 6]
separation = [
    [0, 4, 5, 3, 4],
    [4, 0, 4, 5, 3],
    [5, 4, 0, 4, 5],
    [3, 5, 4, 0, 4],
    [4, 3, 5, 4, 0],
]

n = len(earliest)
model = cp_model.CpModel()

landing = [
    model.NewIntVar(earliest[i], latest[i], f"landing_{i}")
    for i in range(n)
]
early = [
    model.NewIntVar(0, max(target[i] - earliest[i], 0), f"early_{i}")
    for i in range(n)
]
late = [
    model.NewIntVar(0, max(latest[i] - target[i], 0), f"late_{i}")
    for i in range(n)
]

order = {}
horizon = max(latest) - min(earliest) + max(max(row) for row in separation)
for i in range(n):
    for j in range(n):
        if i != j:
            order[i, j] = model.NewBoolVar(f"order_{i}_{j}")

for i in range(n):
    model.Add(early[i] >= target[i] - landing[i])
    model.Add(late[i] >= landing[i] - target[i])

for i in range(n):
    for j in range(i + 1, n):
        model.Add(order[i, j] + order[j, i] == 1)

for i in range(n):
    for j in range(n):
        if i != j:
            model.Add(landing[j] >= landing[i] + separation[i][j] - horizon * (1 - order[i, j]))

model.Minimize(
    sum(penalty_before[i] * early[i] + penalty_after[i] * late[i] for i in range(n))
)

solver = cp_model.CpSolver()
