import json
from ortools.linear_solver import pywraplp

supply = [[18, 22], [27, 13]]
demand = [[20, 15], [25, 20]]
limit = [[24, 20], [18, 25]]
cost = [[[5, 2], [3, 6]], [[4, 3], [2, 5]]]

num_origins = len(supply)
num_destinations = len(demand)
num_products = len(supply[0])

solver = pywraplp.Solver.CreateSolver("GLOP")
transport = {}
for i in range(num_origins):
    for j in range(num_destinations):
        for p in range(num_products):
            transport[i, j, p] = solver.NumVar(0, solver.infinity(), f"transport_{i}_{j}_{p}")

for i in range(num_origins):
    for p in range(num_products):
        solver.Add(sum(transport[i, j, p] for j in range(num_destinations)) == supply[i][p])

for j in range(num_destinations):
    for p in range(num_products):
        solver.Add(sum(transport[i, j, p] for i in range(num_origins)) == demand[j][p])

for i in range(num_origins):
    for j in range(num_destinations):
        solver.Add(sum(transport[i, j, p] for p in range(num_products)) <= limit[i][j])

solver.Minimize(
    sum(cost[i][j][p] * transport[i, j, p]
        for i in range(num_origins)
        for j in range(num_destinations)
        for p in range(num_products))
)

solver.Solve()
result = [int(round(solver.Objective().Value()))]
print(json.dumps(result))

