from ortools.linear_solver import pywraplp

supply = [10, 8]
demand = [6, 5, 7]
cost = [
    [18, 12, 20],
    [15, 17, 14],
]
limit = [
    [6, 5, 6],
    [4, 5, 7],
]

solver = pywraplp.Solver.CreateSolver("GLOP")
assign = {}
for i in range(len(supply)):
    for j in range(len(demand)):
        assign[i, j] = solver.NumVar(0, limit[i][j], f"assign_{i}_{j}")

for i in range(len(supply)):
    solver.Add(sum(assign[i, j] for j in range(len(demand))) == supply[i])

for j in range(len(demand)):
    solver.Add(sum(assign[i, j] for i in range(len(supply))) == demand[j])

solver.Minimize(
    sum(cost[i][j] * assign[i, j] for i in range(len(supply)) for j in range(len(demand)))
)

status = solver.Solve()
if status != pywraplp.Solver.OPTIMAL:
    raise RuntimeError("No optimal solution found")

result = [int(round(solver.Objective().Value()))]
print(json.dumps(result))
